mapper.select:
SELECT * FROM customer_t
WHERE active = 0

    AND grade = #{grade}

ORDER BY c_idx DESC
LIMIT #{numPerPage} OFFSET #{offset}

mapper.update:
UPDATE customer_t
SET visit_count    = visit_count + 1,
    monthly_visit  = monthly_visit + 1,
    monthly_amount = monthly_amount + #{amount}
WHERE c_idx = #{c_idx}

mapper.delete:
DELETE FROM customer_tag_t
WHERE c_idx = #{c_idx} AND tag = #{tag}
LIMIT 1

mapper.select:
SELECT * FROM customer_t
WHERE active = 0
  AND (name LIKE #{keyword} OR phone LIKE #{keyword})

    AND grade = #{grade}

ORDER BY c_idx DESC
LIMIT #{numPerPage} OFFSET #{offset}
